={{ (() => {
  const fields = $json.data?.card?.fields ?? [];
  const byId = Object.fromEntries(fields.map((field) => [field?.field?.id, field]));
  const clean = (value) => String(value ?? '').trim();
  const hasValue = (value) => value !== undefined && value !== null && clean(value) !== '';
  const scalarFromField = (field) => {
    if (!field) return '';
    const candidates = [field.report_value, field.value, field.native_value];
    for (const candidate of candidates) {
      if (Array.isArray(candidate)) {
        if (candidate.length > 0) return candidate[0];
        continue;
      }
      if (hasValue(candidate)) return candidate;
    }
    if (Array.isArray(field.array_value) && field.array_value.length === 1) return field.array_value[0];
    return '';
  };
  const normalizeNumericSource = (value) => {
    let source = clean(value);
    if (!source) return '';
    source = source.replace(/[^0-9,.-]/g, '');
    if (!source) return '';
    if (source.includes(',') && source.includes('.')) {
      if (source.lastIndexOf(',') > source.lastIndexOf('.')) {
        source = source.replace(/\./g, '').replace(',', '.');
      } else {
        source = source.replace(/,/g, '');
      }
    } else if (source.includes(',')) {
      source = source.replace(',', '.');
    }
    return source;
  };
  const parseNum = (value) => {
    if (value === undefined || value === null) return 0;
    if (typeof value === 'number' && Number.isFinite(value)) return value;
    const source = normalizeNumericSource(value);
    if (!source) return 0;
    const parsed = Number(source);
    return Number.isFinite(parsed) ? parsed : 0;
  };
  const numericInfoFromValue = (value) => {
    if (value === undefined || value === null) return { raw: '', value: 0, isPresent: false, isValid: false };
    if (typeof value === 'number') {
      return Number.isFinite(value)
        ? { raw: String(value), value, isPresent: true, isValid: true }
        : { raw: String(value), value: 0, isPresent: true, isValid: false };
    }
    const raw = clean(value);
    if (!raw) return { raw: '', value: 0, isPresent: false, isValid: false };
    const normalized = normalizeNumericSource(raw);
    if (!normalized) return { raw, value: 0, isPresent: true, isValid: false };
    const parsed = Number(normalized);
    return Number.isFinite(parsed)
      ? { raw, value: parsed, isPresent: true, isValid: true }
      : { raw, value: 0, isPresent: true, isValid: false };
  };
  const pushId = (bucket, value) => {
    if (value === undefined || value === null) return;
    if (Array.isArray(value)) {
      for (const item of value) pushId(bucket, item);
      return;
    }
    if (typeof value === 'object') {
      if (value.id != null) bucket.push(String(value.id));
      else if (value.value != null) bucket.push(String(value.value));
      else if (value.label != null) bucket.push(String(value.label));
      return;
    }
    const source = clean(value);
    if (!source) return;
    const matches = source.match(/[0-9]+/g);
    if (matches) {
      for (const match of matches) bucket.push(String(match));
      return;
    }
    bucket.push(source);
  };
  const extractIds = (fieldId) => {
    const field = byId[fieldId];
    const out = [];
    if (!field) return out;
    if (Array.isArray(field.array_value)) {
      for (const value of field.array_value) pushId(out, value);
    }
    if (Array.isArray(field.connectedRepoItems)) {
      for (const item of field.connectedRepoItems) pushId(out, item?.id ?? item?.title);
    }
    pushId(out, scalarFromField(field));
    return Array.from(new Set(out.filter(Boolean)));
  };
  const extractList = (fieldId) => {
    const field = byId[fieldId];
    const out = [];
    const push = (value) => {
      if (value === undefined || value === null) return;
      if (Array.isArray(value)) {
        for (const item of value) push(item);
        return;
      }
      if (typeof value === 'object') {
        if (value.title != null) out.push(clean(value.title));
        else if (value.label != null) out.push(clean(value.label));
        else if (value.value != null) out.push(clean(value.value));
        return;
      }
      const source = clean(value);
      if (!source) return;
      if (source.startsWith('[')) {
        try {
          const parsed = JSON.parse(source);
          push(parsed);
          return;
        } catch (_error) {}
      }
      if (source.includes(',')) {
        for (const part of source.split(',')) push(part);
        return;
      }
      out.push(source);
    };
    if (!field) return out;
    if (Array.isArray(field.array_value)) {
      for (const value of field.array_value) push(value);
    }
    if (Array.isArray(field.connectedRepoItems)) {
      for (const item of field.connectedRepoItems) push(item?.title ?? item?.id);
    }
    push(scalarFromField(field));
    return Array.from(new Set(out.map(clean).filter(Boolean)));
  };
  const text = (fieldId) => clean(scalarFromField(byId[fieldId]));
  const number = (fieldId) => Number(parseNum(scalarFromField(byId[fieldId])));
  const numericInfo = (fieldId) => numericInfoFromValue(scalarFromField(byId[fieldId]));
  const currency = text('moeda_da_fatura');
  const activeSuffix = currency === 'USD - $' ? 'usd' : 'brl';
  const activeBaseField = activeSuffix === 'usd' ? 'valor_de_base_usd' : 'valor_de_base_brl';
  const activeSubtotalField = activeSuffix === 'usd' ? 'valor_total_do_item_usd' : 'valor_total_do_item_brl';
  const activeFinalField = activeSuffix === 'usd' ? 'valor_total_do_item_com_descontos_usd' : 'valor_total_do_item_com_descontos_brl';
  const activeUnitField = activeSuffix === 'usd' ? 'valor_unit_rio_usd' : 'valor_unit_rio_brl';
  const activeNominalField = activeSuffix === 'usd' ? 'valor_nominal_a_ser_descontado_usd' : 'valor_nominal_a_ser_descontado_brl';
  const selectedCategories = extractList('categorias_do_saas_isentas_ou_com_desconto');
  const categorySuffixMap = {
    'A&B': 'a_b',
    'E&S': 'e_s',
    'Hospedagem': 'hospedagem',
    'Espaços': 'espa_os',
    'Outros': 'outros',
  };
  const categoryTypeFieldMap = {
    'A&B': 'tipo_de_desconto_a_b_1',
    'E&S': 'tipo_de_desconto_e_s',
    'Hospedagem': 'tipo_de_desconto_hospedagem',
    'Espaços': 'tipo_de_desconto_espa_os',
    'Outros': 'tipo_de_desconto_outros',
  };
  const validCategorySubtypes = ['1260337139', '1260337244', '1260337296'];
  const categoryEntries = selectedCategories.map((category) => {
    const categorySuffix = categorySuffixMap[category] || '';
    const subtypeFieldId = categoryTypeFieldMap[category] || '';
    const selectedSubtypes = subtypeFieldId ? extractIds(subtypeFieldId) : [];
    const baseField = categorySuffix ? `valor_base_saas_categoria_${categorySuffix}_${activeSuffix}` : '';
    const discountPercentField = categorySuffix ? `desconto_no_valor_vari_vel_do_saas_para_${categorySuffix}` : '';
    const taxPercentField = categorySuffix ? `valor_do_imposto_a_ser_isento_${categorySuffix}` : '';
    const baseInfo = baseField ? numericInfo(baseField) : { raw: '', value: 0, isPresent: false, isValid: false };
    const discountPercentInfo = discountPercentField ? numericInfo(discountPercentField) : { raw: '', value: 0, isPresent: false, isValid: false };
    const taxPercentInfo = taxPercentField ? numericInfo(taxPercentField) : { raw: '', value: 0, isPresent: false, isValid: false };
    return {
      category,
      categorySuffix,
      subtypeFieldId,
      selectedSubtypes,
      baseField,
      baseValue: Number(baseInfo.value || 0),
      baseValueIsPresent: baseInfo.isPresent === true,
      baseValueIsValid: baseInfo.isValid === true,
      discountPercentField,
      discountPercent: Number(discountPercentInfo.value || 0),
      discountPercentIsPresent: discountPercentInfo.isPresent === true,
      discountPercentIsValid: discountPercentInfo.isValid === true,
      taxPercentField,
      taxPercent: Number(taxPercentInfo.value || 0),
      taxPercentIsPresent: taxPercentInfo.isPresent === true,
      taxPercentIsValid: taxPercentInfo.isValid === true,
    };
  });
  const selectedCategorySubtypes = [];
  for (const entry of categoryEntries) {
    for (const subtype of entry.selectedSubtypes) {
      if (!selectedCategorySubtypes.includes(subtype)) selectedCategorySubtypes.push(subtype);
    }
  }
  const selectedCategory = categoryEntries.length === 1 ? categoryEntries[0].category : '';
  const selectedCategorySubtype = categoryEntries.length === 1 && categoryEntries[0].selectedSubtypes.length === 1
    ? categoryEntries[0].selectedSubtypes[0]
    : '';
  const baseCalcIds = extractIds('base_do_c_lculo_percentual');
  const model = text('modelo_de_cobran_a');
  const validModels = ['Percentual sobre base', 'Por unidade', 'Fixo'];
  const modelValidationErrorMessage = validModels.includes(model)
    ? ''
    : `Modelo de cobrança inválido para cálculo FIN-04: "${model || '[vazio]'}". Esperado: Percentual sobre base, Por unidade ou Fixo.`;
  const isPercentualBaseSaas = model === 'Percentual sobre base' && baseCalcIds.includes('1268890278');
  const percentualBaseValidationErrorMessage = model === 'Percentual sobre base' && !isPercentualBaseSaas
    ? `Base percentual não suportada para cálculo FIN-04: "${baseCalcIds.length > 0 ? baseCalcIds.join(', ') : '[vazio]'}". Esperado: 1268890278 (SaaS).`
    : '';
  const saasBaseSum = Number(
    number(`valor_base_saas_categoria_a_b_${activeSuffix}`) +
    number(`valor_base_saas_categoria_e_s_${activeSuffix}`) +
    number(`valor_base_saas_categoria_espa_os_${activeSuffix}`) +
    number(`valor_base_saas_categoria_hospedagem_${activeSuffix}`) +
    number(`valor_base_saas_categoria_outros_${activeSuffix}`)
  );
  const discountFlag = text('h_algum_desconto_nesse_item') === 'Sim';
  const requestedDiscountTypes = extractList('tipo_de_desconto_no_item');
  const hasDiscount = discountFlag || requestedDiscountTypes.length > 0;
  const validDiscountTypes = ['Nominal', 'Percentual', 'Categorias de propostas'];
  const invalidDiscountTypes = requestedDiscountTypes.filter((value) => !validDiscountTypes.includes(value));
  const hasCategoryDiscount = requestedDiscountTypes.includes('Categorias de propostas');
  const hasNominalDiscount = requestedDiscountTypes.includes('Nominal');
  const hasPercentualDiscount = requestedDiscountTypes.includes('Percentual');
  const isCategoryDiscountEligible = model === 'Percentual sobre base' && isPercentualBaseSaas;
  const categoryEligibilityErrorMessage = hasCategoryDiscount && !isCategoryDiscountEligible
    ? 'Categorias de propostas só é suportado para Percentual sobre base com base SaaS (1268890278) no FIN-04.'
    : '';
  let discountValidationErrorMessage = '';
  if (hasDiscount) {
    if (requestedDiscountTypes.length === 0) {
      discountValidationErrorMessage = 'Tipo de desconto ausente para item com desconto marcado em FIN-04.';
    } else if (invalidDiscountTypes.length > 0) {
      discountValidationErrorMessage = `Tipo de desconto inválido para cálculo FIN-04: "${invalidDiscountTypes.join(', ')}". Esperado: Nominal, Percentual ou Categorias de propostas.`;
    } else if (categoryEligibilityErrorMessage) {
      discountValidationErrorMessage = categoryEligibilityErrorMessage;
    }
  }
  const unknownCategories = selectedCategories.filter((category) => !categorySuffixMap[category] || !categoryTypeFieldMap[category]);
  const missingSubtypeEntry = categoryEntries.find((entry) => entry.selectedSubtypes.length === 0);
  const invalidSubtypeEntry = categoryEntries.find((entry) => entry.selectedSubtypes.some((subtype) => !validCategorySubtypes.includes(subtype)));
  const baseRequiredEntry = categoryEntries.find((entry) => {
    const requiresBase = entry.selectedSubtypes.includes('1260337139') || entry.selectedSubtypes.includes('1260337296');
    return requiresBase && (!entry.baseValueIsPresent || !entry.baseValueIsValid);
  });
  const discountPercentRequiredEntry = categoryEntries.find((entry) => entry.selectedSubtypes.includes('1260337139') && (!entry.discountPercentIsPresent || !entry.discountPercentIsValid));
  const taxPercentRequiredEntry = categoryEntries.find((entry) => entry.selectedSubtypes.includes('1260337296') && (!entry.taxPercentIsPresent || !entry.taxPercentIsValid));
  let categoryDiscountValidationErrorMessage = '';
  if (hasCategoryDiscount && !categoryEligibilityErrorMessage) {
    if (selectedCategories.length === 0) {
      categoryDiscountValidationErrorMessage = 'Categoria SaaS ausente para desconto por categorias no FIN-04.';
    } else if (unknownCategories.length > 0) {
      categoryDiscountValidationErrorMessage = `Categoria SaaS inválida para desconto por categorias no FIN-04: "${unknownCategories.join(', ')}".`;
    } else if (missingSubtypeEntry) {
      categoryDiscountValidationErrorMessage = `Subtipo de desconto por categoria ausente para "${missingSubtypeEntry.category}" no FIN-04.`;
    } else if (invalidSubtypeEntry) {
      const invalidSubtypes = invalidSubtypeEntry.selectedSubtypes.filter((subtype) => !validCategorySubtypes.includes(subtype));
      categoryDiscountValidationErrorMessage = `Subtipo de desconto por categoria inválido para "${invalidSubtypeEntry.category}" no FIN-04: "${invalidSubtypes.join(', ')}". Esperado: 1260337139, 1260337244 ou 1260337296.`;
    } else if (baseRequiredEntry) {
      categoryDiscountValidationErrorMessage = `Valor base SaaS ausente ou inválido para "${baseRequiredEntry.category}" no FIN-04 no campo "${baseRequiredEntry.baseField}".`;
    } else if (discountPercentRequiredEntry) {
      categoryDiscountValidationErrorMessage = `Percentual de desconto da categoria ausente ou inválido para "${discountPercentRequiredEntry.category}" no FIN-04 no campo "${discountPercentRequiredEntry.discountPercentField}".`;
    } else if (taxPercentRequiredEntry) {
      categoryDiscountValidationErrorMessage = `Percentual de isenção de imposto da categoria ausente ou inválido para "${taxPercentRequiredEntry.category}" no FIN-04 no campo "${taxPercentRequiredEntry.taxPercentField}".`;
    }
  }
  return {
    cardId: String($json.data?.card?.id ?? ''),
    pipeId: String($json.data?.card?.pipe?.id ?? ''),
    type: text('tipo_de_item'),
    model,
    modelValidationErrorMessage,
    currency,
    activeSuffix,
    activeBaseField,
    activeSubtotalField,
    activeFinalField,
    activeUnitField,
    activeNominalField,
    currentBaseValue: number(activeBaseField),
    currentSubtotalValue: number(activeSubtotalField),
    currentFinalValue: number(activeFinalField),
    currentUnitValue: number(activeUnitField),
    quantity: number('quantidade'),
    percentualBase: number('percentual_a_ser_aplicado_na_base'),
    percentualDesconto: number('percentual_de_desconto_a_ser_aplicado'),
    nominalDiscount: number(activeNominalField),
    baseCalcIds,
    isPercentualBaseSaas,
    percentualBaseValidationErrorMessage,
    saasBaseSum,
    discountFlag,
    hasDiscount,
    requestedDiscountTypes,
    invalidDiscountTypes,
    hasCategoryDiscount,
    hasNominalDiscount,
    hasPercentualDiscount,
    isCategoryDiscountEligible,
    categoryEligibilityErrorMessage,
    discountValidationErrorMessage,
    categoryDiscountValidationErrorMessage,
    selectedCategories,
    selectedCategorySubtypes,
    selectedCategory,
    selectedCategorySubtype,
    categoryEntries,
  };
})() }}

={{ (() => {
  const ctx = ($json.calcContext && typeof $json.calcContext === 'object') ? $json.calcContext : {};
  const values = [];
  const pushNumber = (fieldId, nextValue, currentValue, shouldUpdate) => {
    if (!shouldUpdate || !fieldId) return;
    const nextNumber = Number(nextValue);
    const currentNumber = Number(currentValue);
    if (!Number.isFinite(nextNumber)) return;
    const safeCurrent = Number.isFinite(currentNumber) ? currentNumber : 0;
    if (Math.abs(nextNumber - safeCurrent) <= 1e-9) return;
    values.push({ fieldId, value: [nextNumber] });
  };
  pushNumber(ctx.activeBaseField, $json.calcBaseValue, ctx.currentBaseValue, $json.shouldUpdateBaseField === true);
  pushNumber(ctx.activeSubtotalField, $json.calcSubtotal, ctx.currentSubtotalValue, $json.shouldUpdateSubtotalField === true);
  pushNumber(ctx.activeFinalField, $json.calcFinalTotal, ctx.currentFinalValue, $json.shouldUpdateFinalField === true);
  return values;
})() }}
